const raw = $input.first().json;
const b = raw.body || raw;
if (b.message_type && b.message_type !== 'incoming') return [];
if (b.private) return [];

const conv = b.conversation || {};
const sender = conv?.meta?.sender || b.sender || {};
let phone = (sender.phone_number || sender.identifier || '').replace(/[^0-9+]/g,'').replace(/^\+/,'');
if (phone.startsWith('00')) phone = phone.slice(2);

const atts = b.attachments || b.message?.attachments || [];
let mediaType = 'text', mediaUrl = '';
if (atts.length) {
  const a = atts[0];
  mediaUrl = a.data_url || a.file_url || '';
  if ((a.file_type||'').includes('audio')) mediaType = 'voice';
  else if ((a.file_type||'').includes('image')) mediaType = 'image';
}

const text = (b.content || b.message?.content || '').trim();
if (!phone) return [];
if (mediaType === 'text' && !text) return [];

return [{ json: {
  client_id:  String(raw.client_id || b.client_id || ''),
  account_id: String(b.account?.id || conv?.account_id || ''),
  inbox_id:   String(b.inbox?.id || conv?.inbox_id || ''),
  convId:     conv?.id || null,
  phone, name: sender.name || '', text, mediaType, mediaUrl
} }];

const msg = $('Code · Parse').first().json;
const t = $input.first().json;
if (!t || !t.chatwoot_inbox_id) return [];
let flow = {}; try { flow = JSON.parse(t.flow_json || '{}'); } catch(e) {}
let botConfig = {}; try { botConfig = JSON.parse(t.bot_config || '{}'); } catch(e) {}
let qualQuestions = []; try { qualQuestions = JSON.parse(t.qual_questions || '[]'); } catch(e) {}
return [{ json: {
  ...msg,
  chatwoot_base: t.chatwoot_base, chatwoot_account_id: t.chatwoot_account_id, chatwoot_token: t.chatwoot_token,
  nocodb_base: t.nocodb_base, leads_table_id: t.leads_table_id, nocodb_token: t.nocodb_token,
  openrouter_key: t.openrouter_key, model: t.model || 'google/gemini-2.5-flash',
  language: t.language || 'ml', main_prompt: t.main_prompt || '', flow,
  botConfig, qualQuestions
} }];

const c = $('Code · Build ctx').first().json;
const r = $input.first().json;
const lead = (r.list && r.list[0]) ? r.list[0] : null;
if (lead && (lead.Handover === 'Yes' || lead.Stage === 'human_handover')) return [];

// parse conversation history from lead record
let history = [];
try { history = JSON.parse(lead?.ConvHistory || '[]'); } catch(e) {}

// anti-loop: check if last 3 bot messages are identical
const botMsgs = history.filter(m => m.role === 'assistant').slice(-3).map(m => m.content);
const looping = botMsgs.length === 3 && botMsgs.every(m => m === botMsgs[0]);

// memory: summarise if history is long (> 20 messages)
let memSummary = lead?.MemSummary || '';
let activeHistory = history;
if (history.length > 20 && c.botConfig?.memory_enabled !== false) {
  // keep summary + last 6 messages
  activeHistory = history.slice(-6);
}

return [{ json: { ...c, leadId: lead?.Id || null, stage: lead?.Stage || 'new', history, activeHistory, memSummary, looping } }];

const c = $('Code · State').first().json;
const r = $input.first().json;
const txt = r.choices?.[0]?.message?.content || '(image received)';
return [{ json: { ...c, userText: txt } }];

const c = $('Code · State').first().json;
const r = $input.first().json;
const txt = r.choices?.[0]?.message?.content || '(voice note received)';
return [{ json: { ...c, userText: txt } }];

// Merge all three text paths into one node before intent classification
const c = $input.first().json;
return [{ json: c }];

const c = $input.first().json;
const raw = c.choices?.[0]?.message?.content || '';
let intent = 'SHORT_NEUTRAL', intentData = {};
try {
  const m = raw.replace(/```json|```/gi,'').match(/\{[\s\S]*\}/);
  if (m) {
    const parsed = JSON.parse(m[0]);
    intent = parsed.intent || intent;
    intentData = parsed.data || {};
  }
} catch(e) {}
const valid = ['DELAY','BOOKING','AFFIRMATIVE','WATCHED','FORM_DONE','WANTS_MORE_INFO','QUESTION','WANTS_HUMAN','SHORT_NEUTRAL'];
if (!valid.includes(intent)) intent = 'SHORT_NEUTRAL';

// anti-loop: if looping and no progress, force human
const sc = $('Code · State').first().json;
if (sc.looping && sc.botConfig?.antiloop_enabled !== false) {
  intent = 'WANTS_HUMAN';
}

// Determine if we should run lead qualification first
const qs = sc.qualQuestions || [];
const qDone = (sc.leadId && sc.stage !== 'new') || qs.length === 0 || sc.botConfig?.qual_enabled === false;
const qualStage = sc.stage?.startsWith('qual_') ? parseInt(sc.stage.replace('qual_','')) : null;

// flow lookup
const flow = sc.flow || {};
const node = (flow.stages && (flow.stages[sc.stage] || flow.stages['new'])) || {};
const action = node[intent] || node['*'] || { next: sc.stage, msg: null };

let route = 'stage';
if (intent === 'WANTS_HUMAN' && sc.botConfig?.handover_enabled !== false) route = 'human';
else if (intent === 'QUESTION') route = 'faq';
else if (!qDone && qualStage === null) route = 'qualify'; // start qualification
else if (!qDone && qualStage !== null) route = 'qualify_next'; // continue qualification

// build reply text for stage route
let reply = '', videoUrl = null;
if (route === 'stage' && action.msg) {
  const vars = flow.variables || {};
  reply = (flow.messages?.[action.msg] || '').replace(/\[(\w+)\]/g, (_,k)=> vars[k.toLowerCase()] ?? vars[k] ?? '');
  if (action.form && vars.form_link && !reply.includes(vars.form_link)) reply += '\n\n' + vars.form_link;
  if (action.video) videoUrl = vars[action.video] || null;
}

return [{ json: { ...sc, userText: c.userText, intent, intentData, route, next: action.next || sc.stage, reply, videoUrl, qualStage } }];

// Build FAQ call with conversation history for context
const c = $input.first().json;
const history = c.activeHistory || [];
const memSummary = c.memSummary || '';
let systemPrompt = c.main_prompt;
if (memSummary) systemPrompt += '\n\n[Earlier context summary: ' + memSummary + ']';
const messages = [
  { role: 'system', content: systemPrompt },
  ...history.slice(-8), // last 8 exchanges for context
  { role: 'user', content: c.userText }
];
return [{ json: { ...c, _faqMessages: messages } }];

const c = $('Code · FAQ prep').first().json;
const r = $input.first().json;
const reply = r.choices?.[0]?.message?.content?.trim() || 'Sir/Madam, ഒരു moment 🙏';
return [{ json: { ...c, reply } }];

// Start lead qualification: ask first qualifying question
const c = $input.first().json;
const qs = c.qualQuestions || [];
const question = qs[0] || 'Could you tell me a bit more about what you are looking for?';
return [{ json: { ...c, reply: question, next: 'qual_0' } }];

// Continue qualification: save previous answer, ask next question or move on
const c = $input.first().json;
const qs = c.qualQuestions || [];
const currentIdx = c.qualStage !== null ? c.qualStage : 0;
const nextIdx = currentIdx + 1;
let reply, next, qualAnswers = {};
try { qualAnswers = JSON.parse(c.leadQualAnswers || '{}'); } catch(e) {}
// Store the current answer keyed by question
if (qs[currentIdx]) qualAnswers[qs[currentIdx]] = c.userText;
if (nextIdx < qs.length) {
  // more questions
  reply = qs[nextIdx];
  next = 'qual_' + nextIdx;
} else {
  // qualification complete — move to the first real stage
  const flow = c.flow || {};
  const firstStage = Object.keys(flow.stages || {})[0] || 'new';
  const action = (flow.stages?.[firstStage] || {})['*'] || { next: firstStage, msg: null };
  const vars = flow.variables || {};
  reply = (flow.messages?.[action.msg] || 'Great, thanks! Let me share some information with you 😊').replace(/\[(\w+)\]/g, (_,k)=> vars[k] ?? '');
  next = action.next || firstStage;
}
return [{ json: { ...c, reply, next, leadQualAnswers: JSON.stringify(qualAnswers) } }];

// Summarise conversation if history is getting long (called before upsert)
const c = $input.first().json;
// Append current exchange to history
const history = c.history || [];
if (c.userText) history.push({ role: 'user', content: c.userText });
if (c.reply) history.push({ role: 'assistant', content: c.reply });

const isHuman = c.route === 'human';
const body = {
  Phone: c.phone, Name: c.name, ConversationID: c.convId,
  Date: new Date().toISOString(), Language: c.language,
  ConvHistory: JSON.stringify(history.slice(-40)), // keep last 40 messages
};
if (c.leadQualAnswers) body.QualAnswers = c.leadQualAnswers;
if (isHuman) { body.Stage = 'human_handover'; body.Handover = 'Yes'; }
else { body.Stage = c.next; }
if (!isHuman && c.next !== c.stage) {
  body['Follow up 1']='No'; body['Follow up 2']='No'; body['Follow up 3']='No';
}
if (c.intentData?.booking_time) body.BookingTime = c.intentData.booking_time;
const method = c.leadId ? 'PATCH' : 'POST';
if (c.leadId) body.Id = c.leadId;
return [{ json: { ...c, _method: method, _body: body } }];
